'use client';

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { Database, Sprout, CheckCircle2, AlertTriangle, ArrowRight } from 'lucide-react';
import { seedProducts } from '@/lib/seed';
import Navbar from '@/components/layout/Navbar';
import Footer from '@/components/layout/Footer';

export default function SeedPage() {
  const [isSeeding, setIsSeeding] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState('');

  const handleSeed = async () => {
    setIsSeeding(true);
    setError('');
    setIsSuccess(false);

    try {
      await seedProducts();
      setIsSuccess(true);
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Seeding failed. Check console for details.');
    } finally {
      setIsSeeding(false);
    }
  };

  return (
    <main className="min-h-screen bg-[#fbf9f5]">
      <Navbar />

      <section className="pt-32 pb-20 px-6">
        <div className="max-w-2xl mx-auto">
          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            className="bg-white rounded-3xl shadow-2xl overflow-hidden border border-black/5"
          >
            <div className="bg-[#122c1f] p-8 text-white">
              <div className="flex items-center gap-4 mb-4">
                <Database className="w-8 h-8 text-secondary" />
                <h1 className="text-2xl font-serif font-bold">Samiti Database Control</h1>
              </div>
              <p className="text-white/70 text-sm">
                Use this utility to populate the marketplace with initial organic products and committee essentials.
              </p>
            </div>

            <div className="p-8 space-y-8">
              {!isSuccess ? (
                <>
                  <div className="p-4 bg-amber-50 border border-amber-100 rounded-xl flex items-start gap-4 text-amber-800 text-sm">
                    <AlertTriangle className="w-6 h-6 shrink-0 text-amber-600" />
                    <div>
                      <p className="font-bold mb-1">Attention Required</p>
                      <p>This action will add 3 premium mock products to your Firestore collection. Ensure your Firebase configuration is active.</p>
                    </div>
                  </div>

                  {error && (
                    <div className="p-4 bg-red-50 border border-red-100 rounded-xl text-red-600 text-sm">
                      {error}
                    </div>
                  )}

                  <div className="space-y-4">
                    <h3 className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">Products to be Added</h3>
                    <ul className="space-y-2">
                       {['Pure Sharbati Wheat', 'Raw Forest Honey', 'Organic Desi Ghee'].map((p) => (
                         <li key={p} className="flex items-center gap-3 text-[#122c1f] font-medium">
                           <Sprout className="w-4 h-4 text-green-600" />
                           {p}
                         </li>
                       ))}
                    </ul>
                  </div>

                  <button
                    onClick={handleSeed}
                    disabled={isSeeding}
                    className="w-full py-4 bg-[#122c1f] text-white rounded-xl font-bold flex items-center justify-center gap-2 hover:shadow-xl transition-all disabled:opacity-50"
                  >
                    {isSeeding ? (
                      <motion.div
                        animate={{ rotate: 360 }}
                        transition={{ duration: 1, repeat: Infinity, ease: 'linear' }}
                        className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full"
                      />
                    ) : (
                      <>
                        Begin Seeding Process
                        <ArrowRight className="w-5 h-5" />
                      </>
                    )}
                  </button>
                </>
              ) : (
                <div className="text-center space-y-6 py-10">
                  <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto text-green-600">
                    <CheckCircle2 className="w-10 h-10" />
                  </div>
                  <div className="space-y-2">
                    <h2 className="text-2xl font-serif font-bold text-[#122c1f]">Seeding Complete!</h2>
                    <p className="text-[#77574d] text-sm">The marketplace is now populated with premium heritage products.</p>
                  </div>
                  <div className="flex gap-4 justify-center pt-4">
                    <a href="/marketplace" className="px-8 py-3 bg-[#122c1f] text-white rounded-xl font-bold hover:shadow-lg transition-all">
                      View Marketplace
                    </a>
                    <button 
                      onClick={() => setIsSuccess(false)}
                      className="px-8 py-3 border border-[#122c1f]/10 text-[#122c1f] rounded-xl font-bold hover:bg-[#122c1f]/5 transition-all"
                    >
                      Seed More
                    </button>
                  </div>
                </div>
              )}
            </div>
          </motion.div>
        </div>
      </section>

      <Footer />
    </main>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { addDoc, collection, serverTimestamp } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { useLanguage } from '@/context/LanguageContext';
import { useCart } from '@/context/CartContext';
import { useAuth } from '@/context/AuthContext';
import Navbar from '@/components/layout/Navbar';
import Footer from '@/components/layout/Footer';
import { MapPin, Loader2, CreditCard, ShieldCheck } from 'lucide-react';

export default function CheckoutPage({ params }: { params: { lang: string } }) {
  const { cart, subtotal, deliveryTotal, clearCart } = useCart();
  const { user } = useAuth();
  const router = useRouter();
  const { dict } = useLanguage();

  const grandTotal = subtotal + deliveryTotal;

  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    fullName: '',
    phone: '',
    address: '',
    city: '',
    state: '',
    pincode: ''
  });

  useEffect(() => {
    if (cart.length === 0) {
      router.push(`/${params.lang}/cart`);
    }
  }, [cart, router, params.lang]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const verifyPaymentAndCreateOrder = async (razorpayResponse: any, orderId: string) => {
    try {
      const response = await fetch('/api/verify-payment', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          razorpay_payment_id: razorpayResponse.razorpay_payment_id,
          razorpay_order_id: razorpayResponse.razorpay_order_id,
          razorpay_signature: razorpayResponse.razorpay_signature,
        })
      });
      const data = await response.json();
      if (data.isOk) {
        // Create order in Firestore
        const sellerIds = [...new Set(cart.map(item => item.sellerId))];

        await addDoc(collection(db, 'orders'), {
          buyerId: user?.uid || 'guest',
          buyerName: formData.fullName,
          items: cart,
          subtotal,
          deliveryTotal,
          totalAmount: grandTotal,
          status: 'pending',
          paymentStatus: 'paid',
          paymentId: razorpayResponse.razorpay_payment_id,
          shippingAddress: formData,
          createdAt: serverTimestamp(),
          sellerIds
        });

        clearCart();
        router.push(`/${params.lang}/dashboard/purchases?success=1`);
      } else {
        alert(dict.checkout.payment_failed);
      }
    } catch (err) {
      console.error(err);
      alert(dict.checkout.payment_error);
    } finally {
      setLoading(false);
    }
  };

  const handlePlaceOrder = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) {
      alert(dict.checkout.login_prompt);
      return;
    }

    setLoading(true);

    try {
      const loadScript = () => new Promise((resolve) => {
        const script = document.createElement("script");
        script.src = "https://checkout.razorpay.com/v1/checkout.js";
        script.onload = () => resolve(true);
        script.onerror = () => resolve(false);
        document.body.appendChild(script);
      });

      const res = await loadScript();
      if (!res) {
        alert(dict.checkout.sdk_failed);
        setLoading(false);
        return;
      }

      // 1. Create order on backend
      const response = await fetch('/api/create-order', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ amount: grandTotal })
      });
      const data = await response.json();

      if (!data.orderId) {
        throw new Error(dict.checkout.order_failed);
      }

      // 2. Open Razorpay
      const options = {
        key: process.env.NEXT_PUBLIC_RAZORPAY_KEY_ID || 'rzp_test_YourKey',
        amount: data.amount,
        currency: "INR",
        name: "Kishan Seva Samiti",
        description: dict.checkout.order_desc,
        order_id: data.orderId,
        handler: async function (response: any) {
          await verifyPaymentAndCreateOrder(response, data.orderId);
        },
        prefill: {
          name: formData.fullName,
          contact: formData.phone,
        },
        theme: {
          color: "#122c1f"
        }
      };

      const paymentObject = new (window as any).Razorpay(options);
      paymentObject.open();

    } catch (error) {
      console.error(error);
      alert(dict.checkout.checkout_error);
      setLoading(false);
    }
  };

  if (cart.length === 0) return null;

  return (
    <div className="min-h-screen bg-[#fbf9f5] flex flex-col">
      <Navbar />

      <main className="flex-1 pt-32 pb-20 px-6">
        <div className="max-w-7xl mx-auto">
          <h1 className="text-4xl font-serif font-bold text-[#122c1f] mb-8">{dict.checkout.title}</h1>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">

            {/* Form */}
            <div className="lg:col-span-2 space-y-8">
              <form id="checkout-form" onSubmit={handlePlaceOrder} className="p-8 bg-white rounded-[32px] border border-black/5 shadow-sm space-y-8">

                <div className="flex items-center gap-3 border-b border-black/5 pb-4">
                  <div className="w-8 h-8 rounded-full bg-[#122c1f]/5 flex items-center justify-center text-[#122c1f]">
                    <MapPin className="w-4 h-4" />
                  </div>
                  <h2 className="text-xl font-serif font-bold text-[#122c1f]">{dict.checkout.shipping_address}</h2>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">{dict.checkout.full_name} *</label>
                    <input required name="fullName" value={formData.fullName} onChange={handleInputChange} className="w-full px-6 py-4 bg-[#fbf9f5] border-none rounded-2xl focus:ring-2 focus:ring-[#122c1f]/10 transition-all font-body" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">{dict.checkout.phone} *</label>
                    <input required name="phone" value={formData.phone} onChange={handleInputChange} className="w-full px-6 py-4 bg-[#fbf9f5] border-none rounded-2xl focus:ring-2 focus:ring-[#122c1f]/10 transition-all font-body" />
                  </div>
                  <div className="space-y-2 md:col-span-2">
                    <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">{dict.checkout.address} *</label>
                    <input required name="address" value={formData.address} onChange={handleInputChange} className="w-full px-6 py-4 bg-[#fbf9f5] border-none rounded-2xl focus:ring-2 focus:ring-[#122c1f]/10 transition-all font-body" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">{dict.checkout.city} *</label>
                    <input required name="city" value={formData.city} onChange={handleInputChange} className="w-full px-6 py-4 bg-[#fbf9f5] border-none rounded-2xl focus:ring-2 focus:ring-[#122c1f]/10 transition-all font-body" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">{dict.checkout.state} *</label>
                    <input required name="state" value={formData.state} onChange={handleInputChange} className="w-full px-6 py-4 bg-[#fbf9f5] border-none rounded-2xl focus:ring-2 focus:ring-[#122c1f]/10 transition-all font-body" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">{dict.checkout.pincode} *</label>
                    <input required name="pincode" value={formData.pincode} onChange={handleInputChange} className="w-full px-6 py-4 bg-[#fbf9f5] border-none rounded-2xl focus:ring-2 focus:ring-[#122c1f]/10 transition-all font-body" />
                  </div>
                </div>
              </form>
            </div>

            {/* Summary */}
            <div className="space-y-6">
              <div className="p-8 bg-white rounded-[32px] border border-black/5 shadow-sm space-y-6 sticky top-24">
                <h3 className="text-xl font-serif font-bold text-[#122c1f]">{dict.checkout.your_order}</h3>

                <div className="space-y-4 max-h-48 overflow-y-auto pr-2 custom-scrollbar">
                  {cart.map(item => (
                    <div key={item.productId} className="flex justify-between text-sm">
                      <span className="text-[#122c1f] truncate max-w-[60%] font-medium">{item.quantity}x {item.name}</span>
                      <span className="text-[#77574d]">₹{item.price * item.quantity}</span>
                    </div>
                  ))}
                </div>

                <div className="space-y-4 text-sm text-[#77574d] pt-4 border-t border-black/5">
                  <div className="flex justify-between">
                    <span>{dict.checkout.subtotal}</span>
                    <span className="font-bold text-[#122c1f]">₹{subtotal}</span>
                  </div>
                  <div className="flex justify-between">
                    <span>{dict.checkout.delivery}</span>
                    <span className="font-bold text-[#122c1f]">₹{deliveryTotal}</span>
                  </div>
                  <div className="pt-4 border-t border-black/5 flex justify-between items-end">
                    <span className="font-bold text-[#122c1f]">{dict.checkout.total}</span>
                    <span className="text-2xl font-serif font-bold text-[#122c1f]">₹{grandTotal}</span>
                  </div>
                </div>

                <button 
                  type="submit"
                  form="checkout-form"
                  disabled={loading}
                  className="w-full py-4 bg-[#122c1f] text-white rounded-2xl font-bold uppercase tracking-[0.2em] flex items-center justify-center gap-2 shadow-xl hover:shadow-[#122c1f]/20 hover:scale-[1.02] transition-all disabled:opacity-50 disabled:hover:scale-100"
                >
                  {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <CreditCard className="w-4 h-4" />}
                  {loading ? dict.checkout.processing : dict.checkout.pay_button}
                </button>

                <div className="flex items-center justify-center gap-2 text-[10px] text-[#77574d]">
                  <ShieldCheck className="w-3 h-3" />
                  {dict.checkout.secure_payment}
                </div>
              </div>
            </div>

          </div>
        </div>
      </main>

      <Footer />
    </div>
  );
}

'use client';

import React from 'react';
import { motion } from 'framer-motion';
import {
  Phone, Mail, MapPin, Clock, Send, MessageCircle,
  ChevronRight, HelpCircle, Share2
} from 'lucide-react';
import { useParams } from 'next/navigation';
import toast, { Toaster } from 'react-hot-toast';

const FAQS = [
  {
    q: 'How do I get my farmer membership card?',
    a: 'Register on our platform, complete your farming profile, and pay the one-time ₹50 membership fee. Your digital card is generated instantly.',
  },
  {
    q: 'When is the referral reward credited?',
    a: 'The ₹7 reward is credited to your wallet only after the referred farmer successfully pays the ₹50 membership fee — not before.',
  },
  {
    q: 'What is the minimum balance to request a withdrawal?',
    a: 'You need a minimum wallet balance of ₹100 to submit a withdrawal request. Admin processes all requests within 24 hours.',
  },
  {
    q: 'How do I start selling my organic products?',
    a: 'After completing membership, go to your Dashboard → My Products → Add New Product. Your listing goes live immediately after review.',
  },
  {
    q: 'Is my UPI information safe?',
    a: 'Yes. Your UPI ID is only visible to our admin team for processing your approved withdrawal. It is never shared publicly.',
  },
];

export default function ContactPage() {
  const params = useParams();
  const [form, setForm] = React.useState({ name: '', phone: '', email: '', message: '' });
  const [sending, setSending] = React.useState(false);
  const [openFaq, setOpenFaq] = React.useState<number | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.name || !form.phone || !form.message) {
      toast.error('Please fill name, phone, and message.');
      return;
    }
    setSending(true);
    // Simulate sending (replace with real API / WhatsApp API / email in production)
    await new Promise(r => setTimeout(r, 1500));
    toast.success('Message sent! We will respond within 24 hours.');
    setForm({ name: '', phone: '', email: '', message: '' });
    setSending(false);
  };

  return (
    <div className="min-h-screen bg-[#fbf9f5]">
      <Toaster position="top-center" />

      {/* Hero */}
      <section className="bg-[#122c1f] text-white py-24 md:py-32 relative overflow-hidden">
        <div className="absolute inset-0 opacity-10" style={{
          backgroundImage: 'radial-gradient(circle at 70% 50%, #77574d 0%, transparent 60%)',
        }} />
        <div className="max-w-6xl mx-auto px-6 relative z-10">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
          >
            <p className="text-[10px] font-bold uppercase tracking-widest text-green-400 mb-4">Get In Touch</p>
            <h1 className="text-5xl md:text-6xl font-serif font-bold mb-4">Contact Us</h1>
            <p className="text-white/60 text-xl max-w-xl">
              Have a question, need support, or want to partner with us? Our team is here to help.
            </p>
          </motion.div>
        </div>
      </section>

      <div className="max-w-6xl mx-auto px-6 py-20">
        <div className="grid lg:grid-cols-5 gap-12">
          {/* Left: Contact Info */}
          <div className="lg:col-span-2 space-y-8">
            <motion.div
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.6 }}
            >
              <h2 className="text-2xl font-serif font-bold text-[#122c1f] mb-6">Reach Us Directly</h2>

              {[
                { icon: Phone, label: 'Helpline', value: '+91 98290 XXXXX', sub: 'Mon–Sat, 9am–6pm', href: 'tel:+919829000000' },
                { icon: MessageCircle, label: 'WhatsApp', value: '+91 98290 XXXXX', sub: 'Quick replies', href: 'https://wa.me/919829000000' },
                { icon: Mail, label: 'Email', value: 'help@kishanseva.in', sub: 'We reply within 24h', href: 'mailto:help@kishanseva.in' },
                { icon: MapPin, label: 'Head Office', value: 'Jaipur, Rajasthan', sub: 'India — 302001', href: '#' },
              ].map((item, i) => (
                <a key={i} href={item.href} target="_blank" rel="noopener noreferrer"
                  className="flex items-start gap-4 bg-white rounded-2xl px-6 py-5 border border-black/5 shadow-sm hover:shadow-md transition-all group mb-3 last:mb-0"
                >
                  <div className="w-10 h-10 rounded-xl bg-[#122c1f]/5 flex items-center justify-center shrink-0 group-hover:bg-[#122c1f] group-hover:text-white transition-colors">
                    <item.icon className="w-5 h-5 text-[#122c1f] group-hover:text-white transition-colors" />
                  </div>
                  <div>
                    <p className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">{item.label}</p>
                    <p className="font-bold text-[#122c1f] mt-0.5">{item.value}</p>
                    <p className="text-xs text-[#77574d] opacity-70">{item.sub}</p>
                  </div>
                  <ChevronRight className="w-4 h-4 text-[#77574d]/30 ml-auto self-center group-hover:translate-x-1 transition-transform" />
                </a>
              ))}
            </motion.div>

            {/* Social */}
            <div>
              <p className="text-[10px] font-bold uppercase tracking-widest text-[#77574d] mb-4">Follow Us</p>
              <div className="flex gap-3">
                {[
                  { label: 'Facebook', href: '#' },
                  { label: 'Instagram', href: '#' },
                  { label: 'WhatsApp', href: 'https://wa.me/919829000000' },
                ].map((s, i) => (
                  <a key={i} href={s.href} aria-label={s.label} target="_blank" rel="noopener noreferrer"
                    className="w-10 h-10 rounded-xl bg-white border border-black/5 flex items-center justify-center text-[#77574d] hover:bg-[#122c1f] hover:text-white hover:border-[#122c1f] transition-all text-xs font-bold"
                  >
                    {s.label.charAt(0)}
                  </a>
                ))}
              </div>
            </div>
          </div>

          {/* Right: Contact Form */}
          <motion.div
            className="lg:col-span-3"
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6, delay: 0.1 }}
          >
            <form onSubmit={handleSubmit} className="bg-white rounded-[32px] border border-black/5 shadow-sm p-10 space-y-6">
              <h2 className="text-2xl font-serif font-bold text-[#122c1f]">Send Us a Message</h2>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">Full Name *</label>
                  <input
                    type="text"
                    value={form.name}
                    onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
                    placeholder="Ramesh Kumar"
                    className="w-full px-5 py-4 bg-[#fbf9f5] rounded-2xl text-[#122c1f] focus:ring-2 focus:ring-[#122c1f]/10 border-none outline-none placeholder:text-[#77574d]/30"
                    required
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">Mobile Number *</label>
                  <input
                    type="tel"
                    value={form.phone}
                    onChange={e => setForm(f => ({ ...f, phone: e.target.value }))}
                    placeholder="+91 XXXXX XXXXX"
                    className="w-full px-5 py-4 bg-[#fbf9f5] rounded-2xl text-[#122c1f] focus:ring-2 focus:ring-[#122c1f]/10 border-none outline-none placeholder:text-[#77574d]/30"
                    required
                  />
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">Email (Optional)</label>
                <input
                  type="email"
                  value={form.email}
                  onChange={e => setForm(f => ({ ...f, email: e.target.value }))}
                  placeholder="your@email.com"
                  className="w-full px-5 py-4 bg-[#fbf9f5] rounded-2xl text-[#122c1f] focus:ring-2 focus:ring-[#122c1f]/10 border-none outline-none placeholder:text-[#77574d]/30"
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">Message *</label>
                <textarea
                  value={form.message}
                  onChange={e => setForm(f => ({ ...f, message: e.target.value }))}
                  placeholder="Tell us how we can help you..."
                  rows={5}
                  className="w-full px-5 py-4 bg-[#fbf9f5] rounded-2xl text-[#122c1f] focus:ring-2 focus:ring-[#122c1f]/10 border-none outline-none resize-none placeholder:text-[#77574d]/30"
                  required
                />
              </div>

              <button
                type="submit"
                disabled={sending}
                className="w-full py-5 bg-[#122c1f] text-white rounded-2xl font-bold uppercase tracking-wider hover:bg-[#122c1f]/90 transition-all disabled:opacity-50 flex items-center justify-center gap-2"
              >
