        setReferrals(recs);
      } catch (err) {
        console.error("Error fetching referrals:", err);
      } finally {
        setLoadingReferrals(false);
      }
    }
    fetchReferrals();
  }, [user]);

  const stats = [
    { 
      name: 'Referral Earnings', 
      value: `₹${userData?.stats?.earnings || 0}`, 
      change: '+₹0 today', 
      icon: Gift, 
      color: 'bg-orange-100 text-orange-600' 
    },
    { 
