'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Wallet, ArrowDownToLine, Clock, CheckCircle2, XCircle,
  AlertCircle, IndianRupee, Gift, TrendingUp
} from 'lucide-react';
import { db } from '@/lib/firebase';
import { collection, query, getDocs, addDoc, serverTimestamp, orderBy } from 'firebase/firestore';
import { useAuth } from '@/context/AuthContext';
import toast, { Toaster } from 'react-hot-toast';

const MIN_WITHDRAWAL = 100;

interface WithdrawalRequest {
  id: string;
  amount: number;
  status: 'pending' | 'completed' | 'rejected';
  requestedAt: any;
  upiId?: string;
}

export default function WalletPage() {
  const { user, userData } = useAuth();
  const [withdrawals, setWithdrawals] = useState<WithdrawalRequest[]>([]);
  const [loadingHistory, setLoadingHistory] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [upiId, setUpiId] = useState('');
  const [withdrawAmount, setWithdrawAmount] = useState('');

  const walletBalance = userData?.walletBalance || 0;

  useEffect(() => {
    if (!user?.uid) { setLoadingHistory(false); return; }
    (async () => {
      try {
        const q = query(
          collection(db, 'withdrawals'),
          orderBy('requestedAt', 'desc')
        );
        const snap = await getDocs(q);
        const myRequests = snap.docs
          .map(d => ({ id: d.id, ...d.data() } as WithdrawalRequest))
          .filter(w => (w as any).userId === user.uid);
        setWithdrawals(myRequests);
      } catch (e) {
        console.error(e);
      } finally {
        setLoadingHistory(false);
      }
    })();
  }, [user]);

  const handleWithdrawRequest = async (e: React.FormEvent) => {
    e.preventDefault();
    const amount = parseFloat(withdrawAmount);

    if (!upiId.trim()) { toast.error('Please enter your UPI ID.'); return; }
    if (isNaN(amount) || amount <= 0) { toast.error('Enter a valid amount.'); return; }
    if (amount > walletBalance) { toast.error(`You can't withdraw more than your balance ₹${walletBalance}.`); return; }
    if (walletBalance < MIN_WITHDRAWAL) {
      toast.error(`Minimum withdrawal balance is ₹${MIN_WITHDRAWAL}. Your current balance is ₹${walletBalance}.`);
      return;
    }

    setSubmitting(true);
    try {
      await addDoc(collection(db, 'withdrawals'), {
        userId: user!.uid,
        userName: userData?.fullName || 'Farmer',
        amount,
        upiId: upiId.trim(),
        status: 'pending',
        requestedAt: serverTimestamp(),
      });
      toast.success('Withdrawal request submitted! Admin will process it within 24 hours.');
      setShowForm(false);
      setUpiId('');
      setWithdrawAmount('');
      // Optimistically add to local state
      setWithdrawals(prev => [{
        id: Date.now().toString(),
        amount,
        status: 'pending',
        requestedAt: { toDate: () => new Date() },
        upiId: upiId.trim(),
      }, ...prev]);
    } catch (err: any) {
      toast.error('Failed to submit request. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  const canWithdraw = walletBalance >= MIN_WITHDRAWAL;

  return (
    <div className="max-w-3xl mx-auto space-y-10">
      <Toaster position="top-center" />

      {/* Balance Hero Card */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="relative bg-[#122c1f] rounded-[40px] p-10 text-white overflow-hidden"
      >
        <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full blur-3xl -mr-20 -mt-20" />
        <div className="relative z-10">
          <div className="flex items-center gap-3 mb-6">
            <div className="w-12 h-12 bg-white/10 rounded-2xl flex items-center justify-center">
              <Wallet className="w-6 h-6 text-green-300" />
            </div>
            <div>
              <p className="text-xs uppercase tracking-widest text-white/50 font-bold">Samiti Wallet</p>
              <p className="text-sm text-white/70">Referral Earnings</p>
            </div>
          </div>

          <div className="mb-8">
            <p className="text-white/50 text-sm mb-1">Available Balance</p>
            <p className="text-6xl font-serif font-bold text-white">₹{walletBalance.toFixed(2)}</p>
          </div>

          {!canWithdraw && (
            <div className="flex items-center gap-2 bg-yellow-500/20 border border-yellow-500/30 rounded-2xl px-5 py-3 mb-6">
              <AlertCircle className="w-4 h-4 text-yellow-300 shrink-0" />
              <p className="text-yellow-200 text-sm">
                Minimum ₹{MIN_WITHDRAWAL} required to withdraw. 
                You need ₹{(MIN_WITHDRAWAL - walletBalance).toFixed(2)} more.
              </p>
            </div>
          )}

          <button
            onClick={() => setShowForm(!showForm)}
            disabled={!canWithdraw}
            className={`flex items-center gap-2 px-8 py-4 rounded-2xl font-bold uppercase tracking-wider text-sm transition-all ${
              canWithdraw
                ? 'bg-white text-[#122c1f] hover:bg-green-50 hover:scale-105 shadow-xl'
                : 'bg-white/10 text-white/30 cursor-not-allowed'
            }`}
          >
            <ArrowDownToLine className="w-4 h-4" />
            Request Withdrawal
          </button>
        </div>
      </motion.div>

      {/* Withdrawal Form */}
      <AnimatePresence>
        {showForm && (
          <motion.form
            key="withdraw-form"
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            onSubmit={handleWithdrawRequest}
            className="bg-white rounded-[32px] border border-black/5 shadow-sm p-8 space-y-6 overflow-hidden"
          >
            <h3 className="text-xl font-serif font-bold text-[#122c1f]">Withdrawal Request</h3>

            <div className="space-y-2">
              <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">UPI ID</label>
              <input
                type="text"
                value={upiId}
                onChange={e => setUpiId(e.target.value)}
                placeholder="yourname@upi"
                className="w-full px-5 py-4 bg-[#fbf9f5] rounded-2xl text-[#122c1f] focus:ring-2 focus:ring-[#122c1f]/10 border-none outline-none"
                required
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">
                Amount (Max: ₹{walletBalance})
              </label>
              <div className="relative">
                <IndianRupee className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-[#77574d]/40" />
                <input
                  type="number"
                  value={withdrawAmount}
                  onChange={e => setWithdrawAmount(e.target.value)}
                  placeholder="Enter amount"
                  max={walletBalance}
                  min={1}
                  className="w-full pl-12 pr-4 py-4 bg-[#fbf9f5] rounded-2xl text-[#122c1f] focus:ring-2 focus:ring-[#122c1f]/10 border-none outline-none"
                  required
                />
              </div>
            </div>

            <p className="text-xs text-[#77574d] bg-[#fbf9f5] rounded-xl px-4 py-3">
              ⚠️ Admin reviews all withdrawal requests within 24 hours. Approved amounts will be sent directly to your UPI ID.
            </p>

            <div className="flex gap-3">
              <button
                type="button"
                onClick={() => setShowForm(false)}
                className="flex-1 py-4 border border-black/10 rounded-2xl font-bold text-[#122c1f] hover:bg-black/5 transition-colors"
              >
                Cancel
              </button>
              <button
                type="submit"
                disabled={submitting}
                className="flex-1 py-4 bg-[#122c1f] text-white rounded-2xl font-bold hover:bg-[#122c1f]/90 transition-colors disabled:opacity-50"
              >
                {submitting ? 'Submitting...' : 'Submit Request'}
              </button>
            </div>
          </motion.form>
        )}
      </AnimatePresence>

      {/* Withdrawal History */}
      <section className="space-y-4">
        <h3 className="text-xl font-serif font-bold text-[#122c1f]">Withdrawal History</h3>
        {loadingHistory ? (
          <div className="text-center py-10 text-[#77574d]">Loading...</div>
        ) : withdrawals.length === 0 ? (
          <div className="bg-white rounded-[32px] border border-black/5 p-10 text-center">
            <TrendingUp className="w-10 h-10 text-[#122c1f]/20 mx-auto mb-3" />
            <p className="text-[#77574d] text-sm">No withdrawal requests yet.</p>
            <p className="text-[#77574d]/60 text-xs mt-1">Earn ₹7 per referral and withdraw when you reach ₹100.</p>
          </div>
        ) : (
          <div className="bg-white rounded-[32px] border border-black/5 overflow-hidden shadow-sm divide-y divide-black/5">
            {withdrawals.map(req => (
              <div key={req.id} className="flex items-center justify-between px-8 py-5">
                <div>
                  <p className="font-bold text-[#122c1f] text-sm">₹{req.amount} → {req.upiId}</p>
                  <p className="text-xs text-[#77574d] mt-0.5">
                    {req.requestedAt?.toDate?.()?.toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }) || 'Pending...'}
                  </p>
                </div>
                <span className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wider ${
                  req.status === 'completed' ? 'bg-green-100 text-green-700' :
                  req.status === 'rejected' ? 'bg-red-100 text-red-700' :
                  'bg-yellow-100 text-yellow-700'
                }`}>
                  {req.status === 'completed' ? <CheckCircle2 className="w-3 h-3" /> :
                   req.status === 'rejected' ? <XCircle className="w-3 h-3" /> :
                   <Clock className="w-3 h-3" />}
                  {req.status}
                </span>
              </div>
            ))}
          </div>
        )}
      </section>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Phone as PhoneIcon, 
  ShieldCheck,
  AlertCircle,
  Key,
  CheckCircle2,
  ArrowRight,
  ArrowLeft,
  Smartphone
} from 'lucide-react';
import { useRouter } from 'next/navigation';
import { 
  RecaptchaVerifier, 
  signInWithPhoneNumber,
  ConfirmationResult,
  updatePassword,
  getAuth,
  signOut
} from 'firebase/auth';
import { auth, db } from '@/lib/firebase';
import { collection, query, where, getDocs } from 'firebase/firestore';
import Navbar from '@/components/layout/Navbar';
import Footer from '@/components/layout/Footer';
import { useLanguage } from '@/context/LanguageContext';
import Link from 'next/link';

declare global {
  interface Window {
    recaptchaVerifier: any;
  }
}

export default function ForgotPasswordPage() {
  const router = useRouter();
  const { dict, lang } = useLanguage();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);

  const [step, setStep] = useState<1 | 2 | 3>(1); // 1: Phone, 2: OTP, 3: New Passcode
  const [formData, setFormData] = useState({
    phone: '',
    otp: '',
    newPasscode: ''
  });

  const [confirmationResult, setConfirmationResult] = useState<ConfirmationResult | null>(null);
  const [countdown, setCountdown] = useState(0);

  useEffect(() => {
    let timer: NodeJS.Timeout;
    if (countdown > 0) {
      timer = setInterval(() => {
        setCountdown((prev) => prev - 1);
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [countdown]);

  // Cleanup recaptcha on unmount
  useEffect(() => {
    return () => {
      if (window.recaptchaVerifier) {
        window.recaptchaVerifier.clear();
        window.recaptchaVerifier = undefined;
      }
    };
  }, []);

  const setupRecaptcha = () => {
    if (!window.recaptchaVerifier) {
      window.recaptchaVerifier = new RecaptchaVerifier(auth, 'recaptcha-container', {
        size: 'invisible'
      });
    }
  };

  const handleSendOTP = async (e?: React.FormEvent) => {
    e?.preventDefault();
    setError('');

    const phone = formData.phone.replace(/\D/g, '');
    if (phone.length < 10) {
      setError(dict.auth.error_phone);
      return;
    }

    setIsSubmitting(true);
    try {
      // First verify user exists
      const usersRef = collection(db, 'users');
      const q = query(usersRef, where('phone', '==', phone));
      const querySnapshot = await getDocs(q);

      if (querySnapshot.empty) {
        setError("This mobile number is not registered. Please register first.");
        setIsSubmitting(false);
        return;
      }

      setupRecaptcha();
      const appVerifier = window.recaptchaVerifier;
      const phoneWithCode = `+91${phone}`;

      const confirmation = await signInWithPhoneNumber(auth, phoneWithCode, appVerifier);
      setConfirmationResult(confirmation);
      setStep(2);
      setCountdown(60);
    } catch (err: any) {
      console.error("OTP Send Error:", err);
      setError(dict.register.errors.otp_send_failed);
      if (window.recaptchaVerifier) {
        window.recaptchaVerifier.clear();
        window.recaptchaVerifier = undefined;
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleVerifyOTP = async (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.otp.length !== 6 || !confirmationResult) {
      setError(dict.auth.error_otp);
      return;
    }

    setIsSubmitting(true);
    setError('');
    try {
      await confirmationResult.confirm(formData.otp);
      setStep(3);
    } catch (err: any) {
      console.error("OTP Verify Error:", err);
      setError('Invalid code. Please check and try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleResetPasscode = async (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.newPasscode.length < 6) {
      setError(dict.register.errors.passcode_min);
      return;
    }

    setIsSubmitting(true);
    setError('');
    try {
      const user = auth.currentUser;
      if (!user) throw new Error("Verification session lost. Please try again.");

      await updatePassword(user, formData.newPasscode);
      setSuccess(true);
      // Log them out so they can log back in with new passcode properly
      await signOut(auth);
    } catch (err: any) {
      console.error("Reset Error:", err);
      setError('Failed to update passcode. ' + (err.message || ''));
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <main className="min-h-screen bg-[#fbf9f5]">
      <Navbar />

      <div className="container mx-auto px-4 py-20">
        <div className="max-w-md mx-auto">
          <Link 
            href={`/${lang}/login`}
            className="inline-flex items-center gap-2 text-[#77574d] hover:text-[#122c1f] transition-colors mb-8 group"
          >
            <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
            <span className="text-xs font-bold uppercase tracking-widest">{dict.forgot.back_login}</span>
          </Link>

          <div className="bg-white rounded-3xl shadow-2xl p-8 md:p-10 border border-black/5">
            {!success ? (
              <div className="space-y-8">
                <div className="space-y-2">
                  <h1 className="text-3xl font-serif font-bold text-[#122c1f]">{dict.forgot.title}</h1>
                  <p className="text-sm text-[#77574d]">{dict.forgot.subtitle}</p>
                </div>

                {error && (
                  <motion.div 
                    initial={{ opacity: 0, y: -10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="p-4 bg-red-50 border border-red-100 rounded-xl flex items-start gap-3 text-red-600 text-sm"
                  >
                    <AlertCircle className="w-5 h-5 shrink-0" />
                    <p>{error}</p>
                  </motion.div>
                )}

                <AnimatePresence mode="wait">
                  {step === 1 && (
                    <motion.form
                      key="step1"
                      initial={{ opacity: 0, x: 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: -20 }}
                      onSubmit={handleSendOTP}
                      className="space-y-6"
                    >
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">{dict.forgot.phone_label}</label>
                        <div className="relative">
                          <PhoneIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-[#77574d]/30" />
                          <input
                            type="tel"
                            required
                            value={formData.phone}
                            onChange={(e) => setFormData({...formData, phone: e.target.value})}
                            className="w-full pl-12 pr-4 py-4 bg-[#fbf9f5] border-none rounded-xl focus:ring-2 focus:ring-[#122c1f]/10 transition-all text-[#122c1f]"
                            placeholder={dict.login.phone_placeholder}
                          />
                        </div>
                      </div>
                      <button
                        type="submit"
                        disabled={isSubmitting}
                        className="w-full py-4 bg-[#122c1f] text-white rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-[#122c1f]/90 transition-all shadow-lg disabled:opacity-50"
                      >
                        {isSubmitting ? "..." : dict.forgot.send_otp}
                        <ArrowRight className="w-4 h-4" />
                      </button>
                    </motion.form>
                  )}

                  {step === 2 && (
                    <motion.form
                      key="step2"
                      initial={{ opacity: 0, x: 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: -20 }}
                      onSubmit={handleVerifyOTP}
                      className="space-y-6"
                    >
                      <div className="p-3 bg-green-50 border border-green-100 rounded-xl flex items-center gap-3 text-green-700 text-xs">
                        <ShieldCheck className="w-4 h-4" />
                        Code sent to {formData.phone}
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">{dict.login.otp_label}</label>
                        <div className="relative">
                          <ShieldCheck className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-[#77574d]/30" />
                          <input
                            type="text"
                            required
                            maxLength={6}
                            value={formData.otp}
                            onChange={(e) => setFormData({...formData, otp: e.target.value.replace(/\D/g, '')})}
                            className="w-full pl-12 pr-4 py-4 bg-[#fbf9f5] border-none rounded-xl focus:ring-2 focus:ring-[#122c1f]/10 transition-all text-[#122c1f] font-mono tracking-[0.5em] text-lg"
                            placeholder="------"
                          />
                        </div>
                      </div>

                      <div className="flex justify-center">
                        {countdown > 0 ? (
                          <p className="text-xs text-[#77574d]">
                            {dict.auth.wait_resend.replace('{seconds}', countdown.toString())}
                          </p>
                        ) : (
                          <button
                            type="button"
                            onClick={handleSendOTP}
                            className="text-xs font-bold text-[#122c1f] hover:underline"
                          >
                            {dict.auth.resend_otp}
                          </button>
                        )}
                      </div>

                      <button
                        type="submit"
                        disabled={isSubmitting}
                        className="w-full py-4 bg-[#122c1f] text-white rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-[#122c1f]/90 transition-all shadow-lg disabled:opacity-50"
                      >
                        {isSubmitting ? "..." : dict.forgot.verify_otp}
                        <ArrowRight className="w-4 h-4" />
                      </button>
                    </motion.form>
                  )}

                  {step === 3 && (
                    <motion.form
                      key="step3"
                      initial={{ opacity: 0, x: 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: -20 }}
                      onSubmit={handleResetPasscode}
                      className="space-y-6"
                    >
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold uppercase tracking-widest text-[#77574d]">{dict.forgot.new_passcode}</label>
                        <div className="relative">
                          <Key className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-[#77574d]/30" />
                          <input
                            type="password"
                            required
                            value={formData.newPasscode}
                            onChange={(e) => setFormData({...formData, newPasscode: e.target.value})}
                            className="w-full pl-12 pr-4 py-4 bg-[#fbf9f5] border-none rounded-xl focus:ring-2 focus:ring-[#122c1f]/10 transition-all text-[#122c1f]"
                            placeholder={dict.forgot.new_passcode_placeholder}
                          />
                        </div>
                      </div>
                      <button
                        type="submit"
                        disabled={isSubmitting}
                        className="w-full py-4 bg-[#122c1f] text-white rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-[#122c1f]/90 transition-all shadow-lg disabled:opacity-50"
                      >
                        {isSubmitting ? "..." : dict.forgot.reset_button}
                        <CheckCircle2 className="w-4 h-4" />
                      </button>
                    </motion.form>
                  )}
                </AnimatePresence>

                <div id="recaptcha-container"></div>
              </div>
            ) : (
              <motion.div 
                initial={{ scale: 0.95, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                className="text-center space-y-6"
              >
                <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto">
                  <CheckCircle2 className="w-10 h-10 text-green-600" />
                </div>
                <div className="space-y-2">
                  <h2 className="text-2xl font-serif font-bold text-[#122c1f]">{dict.forgot.success_title}</h2>
                  <p className="text-sm text-[#77574d]">{dict.forgot.success_desc}</p>
                </div>
                <button
                  onClick={() => router.push(`/${lang}/login`)}
                  className="w-full py-4 bg-[#122c1f] text-white rounded-xl font-bold hover:bg-[#122c1f]/90 transition-all shadow-lg"
                >
                  {dict.forgot.back_login}
                </button>
              </motion.div>
            )}
          </div>
        </div>
      </div>

      <Footer />
    </main>
  );
}

