                    <Search className="w-8 h-8 text-[#122c1f]/20" />
                </div>
                <h3 className="text-2xl font-serif font-bold text-[#122c1f]">No products found</h3>
                <p className="text-[#77574d]">Try adjusting your search or category filters.</p>
            </div>
